class Solution:
    def strWithout3a3b(self, a: int, b: int) -> str:
        result = []
        while a > 0 or b > 0:
            if result and result[-1] == 'a' and a > 0 and b > 0 and result[-2] == 'a':
                result.append('b')
                b -= 1
            elif result and result[-1] == 'b' and a > 0 and b > 0 and result[-2] == 'b':
                result.append('a')
                a -= 1
            elif a > b:
                result.append('a')
                a -= 1
            else:
                result.append('b')
                b -= 1
        return ''.join(result)
